  .btn-active { background: #fff; color: #000; }
  .status { margin-top: 15px; color: #888; font-family: monospace; font-size: 12px; text-align: center; }
</style>
</head>
<body>
  <video id="v" muted autoplay playsinline></video>

  <div class="controls" id="ctrls">
    <button onclick="startStream()" class="btn-primary" id="startBtn">⚡ Start Stream</button>
    <button onclick="switchCam()" class="btn-secondary">🔄 Switch Cam</button>
    <button onclick="setRes('hd')" class="btn-secondary" id="btn-hd">HD</button>
  </div>

  <div id="log" class="status">Ready to connect...</div>

  <script>
    const HOST_ID = "${peerId}";
    let currentFacingMode = 'environment';
    let currentRes = { width: 1280, height: 720 };
    let peer = null;
    let localStream = null;

    function log(m) { document.getElementById('log').innerText = m; }

    async function startStream() {
      try {
        if(localStream) localStream.getTracks().forEach(t => t.stop());

        log("Accessing Camera...");
        localStream = await navigator.mediaDevices.getUserMedia({ 
          video: { 
            facingMode: currentFacingMode,
            width: { ideal: currentRes.width },
            height: { ideal: currentRes.height }
          }, 
          audio: false 
        });

        document.getElementById('v').srcObject = localStream;
        document.getElementById('startBtn').style.display = 'none';

        if(!peer) {
            log("Connecting to Host...");
            peer = new Peer();
            peer.on('open', (id) => {
              callHost();
            });
            peer.on('error', e => log("Peer Error: " + e));
        } else {
            callHost();
        }
      } catch (e) { log("Error: " + e); }
    }

    function callHost() {
        if(!peer) return;
        log("Calling Host...");
        const call = peer.call(HOST_ID, localStream);
        call.on('stream', () => log("Streaming Active ✅"));
        call.on('close', () => log("Call Ended"));
        call.on('error', (e) => log("Call Error: " + e));
    }

    function switchCam() {
        currentFacingMode = currentFacingMode === 'environment' ? 'user' : 'environment';
        startStream();
    }

