    getDevices();
    initializeHostPeer();

    // Initialize DB and load features
    const initAppDB = async () => {
       await initDB(DEFAULT_FEATURES);
       const feats = await getAllFeatures();
       // Sort by order if available, otherwise by id
       feats.sort((a, b) => {
         const orderA = a.order !== undefined ? a.order : a.id;
         const orderB = b.order !== undefined ? b.order : b.id;
         return orderA - orderB;
       });
       setFeaturesList(feats);
    };
    initAppDB();

    return () => {
      stopStream();
      if (peerInstance.current) peerInstance.current.destroy();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // --- Feature Management ---
  const handleAddFeature = async () => {
    if (!newFeature.title || !newFeature.desc || !newFeature.img) {
      alert("Please fill all fields and upload an image.");
      return;
    }

    try {
      await addFeature({
        title: newFeature.title,
        desc: newFeature.desc,
        img: newFeature.img,
        isDefault: false,
        order: featuresList.length // Append to end
      });
      const feats = await getAllFeatures();
      feats.sort((a, b) => (a.order ?? a.id) - (b.order ?? b.id));
      setFeaturesList(feats);
      setNewFeature({ title: '', desc: '', img: null });
      setIsAddingFeature(false);
    } catch (e) {
      console.error("Failed to add feature", e);
      alert("Could not save feature to database.");
    }
  };

  const handleMoveFeature = async (index: number, direction: 'up' | 'down') => {
    if (direction === 'up' && index === 0) return;
    if (direction === 'down' && index === featuresList.length - 1) return;

    const newFeatures = [...featuresList];
    const swapIndex = direction === 'up' ? index - 1 : index + 1;

    // Swap items in the array
    [newFeatures[index], newFeatures[swapIndex]] = [newFeatures[swapIndex], newFeatures[index]];

    // Update order property for all items to match new array index
    // This ensures consistency even if previous data had gaps
    newFeatures.forEach((f, i) => f.order = i);

    setFeaturesList(newFeatures);

    // Persist to DB
    try {
      // Optimistically update all to ensure order consistency
      // In a larger app, we might only update the swapped pair
      for (const f of newFeatures) {
        await updateFeature(f);
      }
    } catch (e) {
      console.error("Failed to update order", e);
    }
  };

  const handleDeleteFeature = async (id: number) => {
    if (confirm("Are you sure you want to delete this feature?")) {
      try {
        await deleteFeature(id);
        const feats = await getAllFeatures();
        feats.sort((a, b) => (a.order ?? a.id) - (b.order ?? b.id));
        setFeaturesList(feats);
      } catch (e) {
        console.error("Failed to delete feature", e);
      }
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setNewFeature(prev => ({ ...prev, img: ev.target?.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  // --- PeerJS Host Initialization (For USB Tethering) ---
  const initializeHostPeer = () => {
    try {
      if (typeof Peer === 'undefined') return;

      const id = 'SG-' + Math.random().toString(36).substr(2, 5).toUpperCase();
      const peer = new Peer(id, { debug: 1 });

      peer.on('open', (id: string) => {
        console.log('✅ Remote Host Ready ID:', id);
        setPeerId(id);
      });

      peer.on('call', (call: any) => {
        console.log("📞 Incoming connection from USB/Remote device...");
        call.answer(); // Answer automatically
        call.on('stream', (remoteStream: MediaStream) => {
          console.log("🎥 Remote stream received!");
          setRemoteStream(remoteStream);
          setIsCameraEnabled(true);
          // Auto-switch to "Remote" in dropdown logic effectively by prioritizing remoteStream
          setShowLinkModal(false);
        });
      });

      peer.on('error', (err: any) => {
        console.error("❌ Peer Connection Error:", err);
      });

      peerInstance.current = peer;
    } catch (e) {
      console.error("PeerJS failed to load", e);
    }
  };

  // --- Helper: Enumerate Devices ---
  const getDevices = async () => {
    try {
      try {
         await navigator.mediaDevices.getUserMedia({ video: true });
      } catch (e) {
         // Ignore
      }

      const devices = await navigator.mediaDevices.enumerateDevices();
      const videoDevices = devices.filter(d => d.kind === 'videoinput');
      setAvailableDevices(videoDevices);

      if (videoDevices.length > 0 && !selectedDeviceId) {
        setSelectedDeviceId(videoDevices[0].deviceId);
      }
    } catch (err) {
      console.error("Error enumerating devices:", err);
    }
  };

  // --- Stream Management ---
  const getResolutionConstraints = (res: VideoResolution) => {
    switch(res) {
      case '4k': return { width: { ideal: 3840 }, height: { ideal: 2160 } };
      case 'fhd': return { width: { ideal: 1920 }, height: { ideal: 1080 } };
      case 'hd': return { width: { ideal: 1280 }, height: { ideal: 720 } };
      default: return {}; // Auto
    }
  };

  const startStream = async (deviceId?: string) => {
    stopStream();
    setCameraError(null);

    // Check if we should show Remote Stream instead of local webcam
    if (remoteStream && deviceId === 'remote') {
       setStream(remoteStream);
       if (videoRef.current) {
         videoRef.current.srcObject = remoteStream;
         videoRef.current.muted = true;
         videoRef.current.play().catch(e => console.error(e));
       }
       return;
    }

    const getMedia = async (constraints: MediaStreamConstraints) => {
      return await navigator.mediaDevices.getUserMedia(constraints);
    };

    try {
      let newStream: MediaStream;
      const targetDeviceId = deviceId || selectedDeviceId;
      const resolutionConstraints = getResolutionConstraints(selectedResolution);

      const baseConstraints = {
        video: {
            deviceId: targetDeviceId ? { exact: targetDeviceId } : undefined,
            ...resolutionConstraints
        }
      };

      try {
        newStream = await getMedia(baseConstraints);
      } catch (err) {
        console.warn("Constraint match failed, trying fallback...", err);
        // Fallback to minimal constraints
        newStream = await getMedia({ 
            video: targetDeviceId ? { deviceId: { exact: targetDeviceId } } : true 
        });
      }

      setStream(newStream);
      if (!isCameraEnabled) setIsCameraEnabled(true);

      if (videoRef.current) {
        videoRef.current.srcObject = newStream;
        videoRef.current.muted = true;

        setTimeout(async () => {
             try {
               await videoRef.current?.play();
             } catch (e) {
               console.error("Error attempting to play video stream:", e);
               setCameraError("Stream loaded but failed to play.");
             }
        }, 100);
      }
    } catch (err: any) {
      handleCameraError(err);
    }
  };

  const handleCameraError = (err: any) => {
     console.error("Camera error:", err);
      let errorMessage = "An unknown error occurred.";
      if (err.name === 'NotAllowedError') errorMessage = "Camera access denied.";
      else if (err.name === 'NotFoundError') errorMessage = "No camera found.";
      else if (err.name === 'NotReadableError') errorMessage = "Camera in use by another app.";
      else if (err.name === 'OverconstrainedError') errorMessage = "Camera doesn't support this resolution.";
      setCameraError(errorMessage);
  }

  const stopStream = () => {
    // Only stop local streams, not the remote one (keep connection alive)
    if (stream && stream !== remoteStream) {
      stream.getTracks().forEach(track => track.stop());
    }
    setStream(null);
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
  };

  useEffect(() => {
    // If remote stream exists, prioritize it or handle selection
