  const renderFeatures = () => {
    return (
      <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
         <div className="bg-white/5 border border-white/10 rounded-[32px] p-8 md:p-12 relative overflow-hidden flex items-center justify-between">
              <div className="relative z-10 max-w-3xl">
                  <h2 className="text-4xl md:text-5xl font-bold text-white mb-6 font-serif">
                     SceneGuard Capabilities
                  </h2>
                  <p className="text-xl text-white/60 leading-relaxed">
                     Advanced AI-powered scene monitoring, anomaly detection, and change tracking system. 
                     Guided by the legendary Bala Holmes.
                  </p>
              </div>

              <div className="z-20 relative hidden md:block">
                  <button 
                    onClick={() => setIsAddingFeature(!isAddingFeature)} 
                    className="flex items-center gap-2 px-6 py-3 bg-fog-accent text-fog-base rounded-2xl font-bold hover:scale-105 transition-all shadow-lg shadow-fog-accent/20"
