                     </div>
                     <div className="space-y-2">
                        <label className="text-sm text-white/60 font-medium ml-1">Description</label>
                        <textarea 
                           placeholder="Describe this feature..."
                           value={newFeature.desc}
                           onChange={(e) => setNewFeature({...newFeature, desc: e.target.value})}
                           rows={3}
                           className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white placeholder-white/30 focus:outline-none focus:border-fog-accent resize-none"
                        />
                     </div>
                  </div>
                  <div className="space-y-4">
                      <div className="h-full bg-black/40 border-2 border-dashed border-white/10 rounded-2xl flex flex-col items-center justify-center relative overflow-hidden group hover:border-white/30 transition-colors">
                          {newFeature.img ? (
                             <img src={newFeature.img} alt="Preview" className="w-full h-full object-cover" />
                          ) : (
                             <div className="text-center p-6">
                                <ImageIcon className="w-8 h-8 text-white/20 mx-auto mb-2" />
                                <span className="text-white/40 text-sm">Upload Image</span>
                             </div>
                          )}
                          <input type="file" accept="image/*" onChange={handleImageUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
                      </div>
                  </div>
               </div>
               <div className="flex justify-end mt-6">
                   <button 
                      onClick={handleAddFeature}
                      disabled={!newFeature.title || !newFeature.desc || !newFeature.img}
                      className="px-8 py-3 bg-status-present text-fog-base rounded-xl font-bold hover:scale-105 transition-all shadow-lg disabled:opacity-50 disabled:scale-100"
                   >
                      Save Feature
                   </button>
               </div>
            </div>
         )}

         <div className="flex flex-col gap-6">
            {featuresList.map((item, index) => (
               <div key={item.id} className="group bg-[#121416] border border-white/10 hover:border-fog-accent/50 p-6 rounded-3xl transition-all duration-300 hover:shadow-2xl hover:-translate-y-1 relative overflow-hidden w-full">
                  <div className="flex items-start gap-6 mb-4">
                      <div className="w-24 h-24 rounded-2xl overflow-hidden border border-white/10 shadow-lg shrink-0">
                           <img src={item.img} alt="" className="w-full h-full object-cover" />
                      </div>
                      <div className="flex-1 min-w-0 relative pt-1">
                          <h3 className="text-xl font-bold text-white mb-2 leading-tight group-hover:text-fog-accent transition-colors pr-6">
                              {item.title}
                          </h3>
                           <div className="w-8 h-1 bg-white/10 rounded-full group-hover:bg-fog-accent transition-colors mb-3" />
                           <p className="text-white/60 text-base leading-relaxed max-w-4xl">
                             {item.desc}
                           </p>

                           {/* Actions (Visible on Hover) */}
                           <div className="absolute top-0 right-0 flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity bg-[#121416]/80 backdrop-blur-sm p-1 rounded-lg">
                               <button 
                                  onClick={() => handleMoveFeature(index, 'up')}
                                  className="p-1.5 text-white/50 hover:text-white hover:bg-white/10 rounded-lg disabled:opacity-30 disabled:hover:bg-transparent"
                                  title="Move Up"
                                  disabled={index === 0}
                               >
                                  <ChevronUp className="w-4 h-4" />
                               </button>
                               <button 
                                  onClick={() => handleMoveFeature(index, 'down')}
                                  className="p-1.5 text-white/50 hover:text-white hover:bg-white/10 rounded-lg disabled:opacity-30 disabled:hover:bg-transparent"
                                  title="Move Down"
                                  disabled={index === featuresList.length - 1}
                               >
                                  <ChevronDown className="w-4 h-4" />
                               </button>
                               <div className="w-px h-4 bg-white/20 mx-1"></div>
                               <button 
                                  onClick={() => handleDeleteFeature(item.id)}
                                  className="p-1.5 text-white/50 hover:text-red-500 hover:bg-red-500/10 rounded-lg"
                                  title="Delete Feature"
                               >
                                  <Trash2 className="w-4 h-4" />
                               </button>
                           </div>
                      </div>
                  </div>
               </div>
            ))}
         </div>
      </div>
    );
  };

  return (
    <Layout currentView={view} onChangeView={setView}>
      {view === 'dashboard' && renderDashboard()}
      {view === 'create-reference' && renderCreateReference()}
      {view === 'monitor' && renderMonitor()}
      {view === 'photo-compare' && renderPhotoCompare()}
      {view === 'features' && renderFeatures()}
      {renderLinkModal()}
    </Layout>
  );
};

export default App;

