// services/db.ts

const DB_VERSION = 2; // Bump version

export const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      const transaction = (event.target as IDBOpenDBRequest).transaction;

      // If store exists, we might want to preserve data or clear it depending on intent.
      // Since we are changing "Default" features in code and want it reflected, 
      // and this is a prototype phase ("It's a Prototype, Relax"), 
      // let's clear and re-seed to match code.

      if (db.objectStoreNames.contains(STORE_NAME)) {
          db.deleteObjectStore(STORE_NAME);
      }
      const store = db.createObjectStore(STORE_NAME, { keyPath: "id", autoIncrement: true });
      store.createIndex("id", "id", { unique: true });
    };

    request.onsuccess = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
