    // If remote stream exists, prioritize it or handle selection
    if ((view === 'create-reference' || view === 'monitor') && isCameraEnabled && !currentFrameImage) {
      if (selectedDeviceId === 'remote' && remoteStream) {
         startStream('remote');
      } else {
         startStream(selectedDeviceId);
