    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [view, selectedDeviceId, isCameraEnabled, currentFrameImage, remoteStream, selectedResolution]);


  // --- Recording Logic ---
  const toggleRecording = () => {
