  // --- HTML Client Generator for USB Tethering ---
  const getManualClientCode = () => {
    return `<!DOCTYPE html>
<html>
<head>
<meta name="viewport" content="width=device-width, initial-scale=1">
<script src="https://unpkg.com/peerjs@1.5.2/dist/peerjs.min.js"></script>
<style>
  body { background: #000; color: #fff; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; display: flex; flex-direction: column; align-items: center; justify-content: flex-start; height: 100vh; margin: 0; padding: 20px; box-sizing: border-box; }
  video { width: 100%; max-height: 50vh; background: #222; border-radius: 12px; margin-bottom: 20px; object-fit: cover; }
  .controls { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; width: 100%; max-width: 400px; }
  button { padding: 14px; font-size: 16px; font-weight: bold; border: none; border-radius: 12px; cursor: pointer; transition: transform 0.1s; }
  button:active { transform: scale(0.95); }
  .btn-primary { background: #00ff88; color: #000; grid-column: span 2; }
  .btn-secondary { background: #333; color: #fff; border: 1px solid #444; }
  .btn-active { background: #fff; color: #000; }
  .status { margin-top: 15px; color: #888; font-family: monospace; font-size: 12px; text-align: center; }
</style>
</head>
<body>
  <video id="v" muted autoplay playsinline></video>

  <div class="controls" id="ctrls">
    <button onclick="startStream()" class="btn-primary" id="startBtn">⚡ Start Stream</button>
    <button onclick="switchCam()" class="btn-secondary">🔄 Switch Cam</button>
    <button onclick="setRes('hd')" class="btn-secondary" id="btn-hd">HD</button>
  </div>

  <div id="log" class="status">Ready to connect...</div>

  <script>
    const HOST_ID = "${peerId}";
    let currentFacingMode = 'environment';
    let currentRes = { width: 1280, height: 720 };
    let peer = null;
    let localStream = null;

    function log(m) { document.getElementById('log').innerText = m; }

    async function startStream() {
      try {
        if(localStream) localStream.getTracks().forEach(t => t.stop());

        log("Accessing Camera...");
        localStream = await navigator.mediaDevices.getUserMedia({ 
          video: { 
            facingMode: currentFacingMode,
            width: { ideal: currentRes.width },
            height: { ideal: currentRes.height }
          }, 
          audio: false 
        });

        document.getElementById('v').srcObject = localStream;
        document.getElementById('startBtn').style.display = 'none';

        if(!peer) {
            log("Connecting to Host...");
            peer = new Peer();
            peer.on('open', (id) => {
              callHost();
            });
            peer.on('error', e => log("Peer Error: " + e));
        } else {
            callHost();
        }
      } catch (e) { log("Error: " + e); }
    }

    function callHost() {
        if(!peer) return;
        log("Calling Host...");
        const call = peer.call(HOST_ID, localStream);
        call.on('stream', () => log("Streaming Active ✅"));
        call.on('close', () => log("Call Ended"));
        call.on('error', (e) => log("Call Error: " + e));
    }

    function switchCam() {
        currentFacingMode = currentFacingMode === 'environment' ? 'user' : 'environment';
        startStream();
    }

    function setRes(type) {
        if(type === 'hd') currentRes = { width: 1280, height: 720 };
        else if(type === 'fhd') currentRes = { width: 1920, height: 1080 };
        startStream();
    }
  </script>
</body>
</html>`;
