      >
        <div className="flex items-center gap-2 overflow-hidden">
          {Icon && <Icon className="w-4 h-4 text-white/50 shrink-0" />}
          <span className="truncate block text-left font-medium text-white/90">
            {selectedOption ? selectedOption.label : <span className="text-white/40">{placeholder}</span>}
          </span>
        </div>
        <ChevronDown className={`w-4 h-4 text-white/50 shrink-0 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute top-full left-0 mt-2 min-w-[100%] w-max max-w-[400px] bg-[#1A1D21] border border-white/10 rounded-xl shadow-2xl overflow-hidden z-[100] max-h-80 overflow-y-auto custom-scrollbar animate-in fade-in zoom-in-95 duration-100">
          <div className="p-1">
            {options.map((opt) => (
              <button
                key={opt.value}
                onClick={() => {
                  onChange(opt.value);
                  setIsOpen(false);
                }}
                className={`w-full text-left px-3 py-2.5 text-sm flex items-center gap-2 rounded-lg transition-colors border border-transparent ${
                  value === opt.value 
                    ? 'bg-white/10 text-white font-medium border-white/5' 
                    : 'text-white/70 hover:bg-white/5 hover:text-white'
                }`}
              >
                <div className={`w-1.5 h-1.5 rounded-full shrink-0 ${value === opt.value ? 'bg-status-present' : 'bg-transparent'}`} />
