    alert("Configuration logged to console (F12)!\n\nTo make these images default for everyone:\n1. Copy the JSON from the console\n2. Paste it into 'DEFAULT_FEATURES' in App.tsx\n3. Deploy.");
  };

  // --- PeerJS Host Initialization (For USB Tethering) ---
  const initializeHostPeer = () => {
    try {
      if (typeof Peer === 'undefined') return;

      const id = 'SG-' + Math.random().toString(36).substr(2, 5).toUpperCase();
      const peer = new Peer(id, { debug: 1 });

      peer.on('open', (id: string) => {
        console.log('✅ Remote Host Ready ID:', id);
        setPeerId(id);
      });

      peer.on('call', (call: any) => {
        console.log("📞 Incoming connection from USB/Remote device...");
        call.answer(); // Answer automatically
        call.on('stream', (remoteStream: MediaStream) => {
          console.log("🎥 Remote stream received!");
          setRemoteStream(remoteStream);
          setIsCameraEnabled(true);
          // Auto-switch to "Remote" in dropdown logic effectively by prioritizing remoteStream
          setShowLinkModal(false);
        });
      });

      peer.on('error', (err: any) => {
        console.error("❌ Peer Connection Error:", err);
      });

      peerInstance.current = peer;
    } catch (e) {
      console.error("PeerJS failed to load", e);
    }
  };

  // --- Helper: Enumerate Devices ---
  const getDevices = async () => {
    try {
      // 1. Force request permission to ensure labels are available
      try {
         const initStream = await navigator.mediaDevices.getUserMedia({ video: true });
         initStream.getTracks().forEach(track => track.stop());
      } catch (e) {
         console.warn("Permission check failed or cancelled", e);
      }

      const devices = await navigator.mediaDevices.enumerateDevices();
      const videoDevices = devices.filter(d => d.kind === 'videoinput');
      setAvailableDevices(videoDevices);

    } catch (err) {
      console.error("Error enumerating devices:", err);
    }
  };

  // --- Stream Management ---
  const startStream = async (deviceId?: string) => {
    setCameraError(null);

    // Check if we should show Remote Stream instead of local webcam
    if (remoteStream && deviceId === 'remote') {
       setStream(remoteStream);
       // NOTE: We don't attach srcObject here anymore, the useEffect handles it
       setIsCameraEnabled(true);
       return;
    }

    const getMedia = async (constraints: MediaStreamConstraints) => {
      return await navigator.mediaDevices.getUserMedia(constraints);
    };

    try {
      let newStream: MediaStream;
      // 'default' uses system default. Specific ID uses that ID.
      const targetDeviceId = (!deviceId || deviceId === 'default') ? undefined : { exact: deviceId };

      const baseConstraints = {
        video: {
            deviceId: targetDeviceId,
            width: { ideal: 1280 },
            height: { ideal: 720 }
        }
      };

      try {
        newStream = await getMedia(baseConstraints);
      } catch (err) {
        console.warn("Constraint match failed, trying fallback...", err);
        newStream = await getMedia({ 
            video: targetDeviceId ? { deviceId: targetDeviceId } : true 
        });
      }

      setStream(newStream);
      setIsCameraEnabled(true);

    } catch (err: any) {
      handleCameraError(err);
      setIsCameraEnabled(false);
    }
  };

  // --- FIX: Video Attachment Effect ---
  // Attaches stream to video element whenever stream/element changes.
  // This solves the issue where video element might not be rendered yet when startStream is called.
  useEffect(() => {
    if (isCameraEnabled && stream && videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.play().catch(e => console.error("Autoplay prevented:", e));
    }
  }, [isCameraEnabled, stream]);


  const handleCameraError = (err: any) => {
     console.error("Camera error:", err);
