    setCopiedCode(true);
    setTimeout(() => setCopiedCode(false), 2000);
  };

  // Updated Camera Options Logic: Prioritize PC Webcam
  const cameraOptions = useMemo(() => {
    const opts = [
        { value: 'default', label: 'PC Webcam (Default)' }
    ];

    if (remoteStream) {
        opts.push({ value: 'remote', label: '⚡ USB/Remote Phone' });
