        dataUrl = captureFrame('high', true); 
        if (dataUrl) break;
        await new Promise(resolve => setTimeout(resolve, 300));
        attempts++;
    }

    if (!dataUrl) {
         console.warn("Timeout waiting for bright frame, capturing anyway.");
