                               <button 
                                  onClick={() => handleMoveFeature(index, 'up')}
                                  className="p-1.5 text-white/50 hover:text-white hover:bg-white/10 rounded-lg disabled:opacity-30 disabled:hover:bg-transparent"
                                  title="Move Up"
                                  disabled={index === 0}
                               >
                                  <ChevronUp className="w-4 h-4" />
                               </button>
                               <button 
                                  onClick={() => handleMoveFeature(index, 'down')}
                                  className="p-1.5 text-white/50 hover:text-white hover:bg-white/10 rounded-lg disabled:opacity-30 disabled:hover:bg-transparent"
                                  title="Move Down"
                                  disabled={index === featuresList.length - 1}
                               >
                                  <ChevronDown className="w-4 h-4" />
                               </button>
                               <div className="w-px h-4 bg-white/20 mx-1"></div>
                               <button 
                                  onClick={() => handleDeleteFeature(item.id)}
                                  className="p-1.5 text-white/50 hover:text-red-500 hover:bg-red-500/10 rounded-lg"
                                  title="Delete Feature"
                               >
                                  <Trash2 className="w-4 h-4" />
                               </button>
                           </div>
                      </div>
                  </div>
               </div>
            ))}
         </div>
      </div>
    );
  };

  return (
    <Layout currentView={view} onChangeView={setView}>
      {view === 'dashboard' && renderDashboard()}
      {view === 'create-reference' && renderCreateReference()}
      {view === 'monitor' && renderMonitor()}
      {view === 'photo-compare' && renderPhotoCompare()}
      {view === 'features' && renderFeatures()}
      {renderLinkModal()}
    </Layout>
  );
};

