  const handleExportConfig = async () => {
    setIsExporting(true);
    try {
        // Compress images to reduce JSON size
        const processedFeatures = await Promise.all(featuresList.map(async (item) => {
            const newItem = { ...item };
            // Only compress if it's a base64 data URL
            if (newItem.img && newItem.img.startsWith('data:')) {
                try {
                    newItem.img = await resizeBase64Image(newItem.img, 400); // Reduce to 400px width
                } catch (e) {
                    console.warn("Failed to compress image for export:", e);
                }
            }
            const { id, ...rest } = newItem; // Remove DB ID
            return rest;
        }));

        const json = JSON.stringify(processedFeatures, null, 2);

        // Use Blob for safety against clipboard limits
