        if (sizeInMB > 0.5) {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = 'sceneguard-config.json';
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
            alert(`⚠️ Config is still large (${sizeInMB.toFixed(2)} MB).\n\nIt has been downloaded as 'sceneguard-config.json'.\n\nYou can share this file with others to Import.`);
