            navigator.clipboard.writeText(json).then(() => {
                alert(`✅ Compressed Configuration COPIED to clipboard!\n\nSize: ${sizeInMB.toFixed(2)} MB\n\nTry pasting this into the chat now.`);
            }).catch(err => {
                console.error("Clipboard write failed", err);
                alert("Clipboard access failed.");
            });
        }
