           <CustomSelect value={activeRefId || ""} options={referenceOptions} onChange={(val) => { setActiveRefId(val); setMonitoringActive(false); }} placeholder="Select Scene to Monitor" icon={Images} className="w-80 shrink-0 z-[50]"/>
